namespace sv_422732272a2e4fb186eb1bf439e5f9d7;

public enum Theme
{
    Light,
    Dark,
    System
}

public class ThemeInfo
{
    public Theme Theme { get; set; } = Theme.Light;
    public string AccentColor { get; set; } = "#0d6efd";
}

@rendermode InteractiveServer

<span class="theme-indicator badge" style="background-color: @(Theme?.AccentColor ?? "#0d6efd");">
    @switch (Theme?.Theme)
    {
        case sv_422732272a2e4fb186eb1bf439e5f9d7.Theme.Dark:
            <text>🌙 Dark</text>
            break;
        case sv_422732272a2e4fb186eb1bf439e5f9d7.Theme.System:
            <text>💻 System</text>
            break;
        default:
            <text>☀️ Light</text>
            break;
    }
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }
}

@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<div class="nav-item px-3 py-2">
    <button class="btn btn-sm btn-outline-light w-100" @onclick="CycleTheme">
        @switch (Theme?.Theme)
        {
            case sv_422732272a2e4fb186eb1bf439e5f9d7.Theme.Dark:
                <text>🌙 Dark</text>
                break;
            case sv_422732272a2e4fb186eb1bf439e5f9d7.Theme.System:
                <text>💻 System</text>
                break;
            default:
                <text>☀️ Light</text>
                break;
        }
    </button>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private async Task CycleTheme()
    {
        if (Theme is null) return;

        Theme.Theme = Theme.Theme switch
        {
            sv_422732272a2e4fb186eb1bf439e5f9d7.Theme.Light => sv_422732272a2e4fb186eb1bf439e5f9d7.Theme.Dark,
            sv_422732272a2e4fb186eb1bf439e5f9d7.Theme.Dark => sv_422732272a2e4fb186eb1bf439e5f9d7.Theme.System,
            _ => sv_422732272a2e4fb186eb1bf439e5f9d7.Theme.Light
        };

        await ThemeSource.NotifyChangedAsync();
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h3>User Preferences</h3>

@if (Theme is not null)
{
    <div class="card mt-3" style="max-width: 400px;">
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label fw-bold">Theme</label>
                <select class="form-select" value="@Theme.Theme" @onchange="OnThemeChanged">
                    @foreach (var t in Enum.GetValues<Theme>())
                    {
                        <option value="@t">@t</option>
                    }
                </select>
            </div>

            <div class="mb-3">
                <label class="form-label fw-bold">Accent Color</label>
                <div class="d-flex align-items-center gap-2">
                    <input type="color" class="form-control form-control-color"
                           value="@Theme.AccentColor" @onchange="OnAccentChanged" />
                    <span class="text-muted">@Theme.AccentColor</span>
                </div>
            </div>

            <div class="alert alert-info mb-0">
                Current: <strong>@Theme.Theme</strong> with accent
                <span class="badge" style="background-color: @Theme.AccentColor;">@Theme.AccentColor</span>
            </div>
        </div>
    </div>
}

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        if (Theme is null || e.Value is not string val) return;
        if (Enum.TryParse<Theme>(val, out var parsed))
        {
            Theme.Theme = parsed;
            await ThemeSource.NotifyChangedAsync();
        }
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        if (Theme is null || e.Value is not string val) return;
        Theme.AccentColor = val;
        await ThemeSource.NotifyChangedAsync();
    }
}

